    'pages.operasional.playbook-incident-response.step_3' => '12-15 minutes: send first official status update to stakeholders.',
    'pages.operasional.playbook-incident-response.step_4' => '2. Define 4 minimum roles: IC, Ops, Comms, Scribe.',
    'pages.operasional.playbook-incident-response.step_5' => '3. Run the fastest reversible mitigation.',
    'pages.operasional.playbook-incident-response.step_6' => '4. Send update #1 in the 15th minute maximum.',
    'pages.operasional.playbook-incident-response.step_7' => '5. Save evidence for RCA/postmortem from the start.',
    'pages.operasional.playbook-incident-response.step_8' => '0-3 minutes: initial triage, determine temporary severity, form channel war-room.',
    'pages.operasional.playbook-incident-response.step_9' => '1. Determine the temporary severity in the first 3 minutes.',
