    'pages.skema.auth-dan-middleware.heading_1' => 'Login Flow and Page Access',
    'pages.skema.auth-dan-middleware.heading_2' => 'Important Auth Route Map',
    'pages.skema.auth-dan-middleware.heading_3' => 'Route Protection in Projects',
    'pages.skema.auth-dan-middleware.heading_4' => 'Custom Middleware: SetLocale',
    'pages.skema.auth-dan-middleware.heading_5' => 'Minimum Security Checklist',
    'pages.skema.auth-dan-middleware.heading_6' => 'Matrix Middleware (Practical)',
    'pages.skema.auth-dan-middleware.heading_7' => 'Team Standard (Strict) Auth',
    'pages.skema.auth-dan-middleware.item_1' => 'The 404 fallback is placed outside of auth to keep error responses consistent.',
    'pages.skema.auth-dan-middleware.item_2' => 'Make sure sensitive routes always reside in the <code>auth</code> middleware.',
    'pages.skema.auth-dan-middleware.item_3' => 'Validate redirects and guard flow during login/logout so that there are no open redirects.',
    'pages.skema.auth-dan-middleware.item_4' => 'Test guest vs authenticated scenarios for each new blueprint page.',
    'pages.skema.auth-dan-middleware.item_5' => '<code>/dashboard</code> uses the middleware <code>auth</code> + <code>verified</code>.',
    'pages.skema.auth-dan-middleware.item_6' => 'All route generators in <code>routes/menu.php</code> are wrapped in the <code>auth</code> middleware.',
    'pages.skema.auth-dan-middleware.item_7' => 'The management profile in <code>routes/web.php</code> is also in the <code>auth</code> group.',
    'pages.skema.auth-dan-middleware.item_8' => 'For critical areas, add <code>verified</code> or other additional middleware as needed.',
    'pages.skema.auth-dan-middleware.item_9' => 'Use <code>signed</code> and <code>throttle</code> as in the email verification route.',
    'pages.skema.auth-dan-middleware.lead' => 'Project security foundation: Laravel built-in auth routes + middleware protection + custom locale middleware.',
    'pages.skema.auth-dan-middleware.note_1' => 'Impact: Users who are not logged in cannot access internal content pages under <code>resources/views/pages</code>.',
    'pages.skema.auth-dan-middleware.step_1' => '2. Submit login to <code>POST /login</code>.',
    'pages.skema.auth-dan-middleware.step_2' => '3. If successful, the auth session is active and the user is redirected to the application page.',
    'pages.skema.auth-dan-middleware.step_3' => '4. Protected routes (dashboard/menu pages) can only be accessed if they pass the <code>auth</code> middleware.',
    'pages.skema.auth-dan-middleware.step_4' => '5. Certain routes also use <code>verified</code> for email verification.',
    'pages.skema.auth-dan-middleware.step_5' => '<strong>Mandatory rule:</strong> sensitive endpoints must use throttling when abuse risk exists.',
    'pages.skema.auth-dan-middleware.step_6' => '<strong>Mandatory rule:</strong> do not expose internal authentication details in user error messages.',
    'pages.skema.auth-dan-middleware.step_7' => '<strong>Mandatory rule:</strong> every auth flow change must be tested for guests, valid users, and unverified users.',
    'pages.skema.auth-dan-middleware.step_8' => '1. Guest access <code>/login</code> (from <code>routes/auth.php</code>).',
    'pages.skema.auth-dan-middleware.step_9' => '<strong>Rule mandatory:</strong> new routes must be clearly classified: public vs auth vs auth+verified.',
    'pages.skema.auth-dan-middleware.warn_1' => 'This middleware runs in the <code>web</code> group, so all web requests automatically follow the locale session.',
