    'pages.skema.cache-dan-deployment.heading_2' => 'Relevant Cache Types',
    'pages.skema.cache-dan-deployment.heading_3' => 'Command Cache Strategy (When to Use)',
    'pages.skema.cache-dan-deployment.heading_4' => 'Runbook Deployment (Minimal Risk)',
    'pages.skema.cache-dan-deployment.heading_5' => 'When to Clear Cache',
    'pages.skema.cache-dan-deployment.heading_6' => 'When Don\'t Clear Everything',
    'pages.skema.cache-dan-deployment.heading_7' => 'Pre-Release Checklist',
    'pages.skema.cache-dan-deployment.heading_8' => 'Post-Release Checklist',
    'pages.skema.cache-dan-deployment.heading_9' => 'Rollback Plan (Required)',
    'pages.skema.cache-dan-deployment.item_1' => 'Improve framework startup performance and response time.',
    'pages.skema.cache-dan-deployment.item_10' => 'When an incident is active without a clear hypothesis regarding the cache.',
    'pages.skema.cache-dan-deployment.item_11' => 'During peak traffic, unless mitigation is absolutely necessary.',
    'pages.skema.cache-dan-deployment.item_12' => 'Use a targeted approach first before clearing completely.',
    'pages.skema.cache-dan-deployment.item_13' => '<strong>Config unchanged:</strong> check <code>.env</code> and run <code>config:cache</code> again.',
    'pages.skema.cache-dan-deployment.item_14' => '<strong>Route error after cache:</strong> look for route closure, change to controller action, then recache.',
    'pages.skema.cache-dan-deployment.item_15' => '<strong>Old view still showing:</strong> run <code>view:clear</code> then <code>view:cache</code>.',
    'pages.skema.cache-dan-deployment.item_16' => '<strong>Queue using old code:</strong> run <code>queue:restart</code> and check supervisor status.',
    'pages.skema.cache-dan-deployment.item_17' => 'Migration impact checklist (large table, lock risk, estimated duration).',
    'pages.skema.cache-dan-deployment.item_18' => 'Confirm backup/restore readiness.',
    'pages.skema.cache-dan-deployment.item_19' => 'Confirm application compatibility during schema transition.',
    'pages.skema.cache-dan-deployment.item_2' => 'Reduces the risk of human error during release.',
    'pages.skema.cache-dan-deployment.item_20' => 'PIC release and PIC data sign approval.',
    'pages.skema.cache-dan-deployment.item_21' => 'Regular deployment only during team-agreed operating hours.',
    'pages.skema.cache-dan-deployment.item_22' => 'Avoid deploying during peak business traffic.',
    'pages.skema.cache-dan-deployment.item_23' => 'Freeze windows are applied during critical business events.',
    'pages.skema.cache-dan-deployment.item_24' => 'Emergency deploy outside the mandatory incident status window + IC approval.',
    'pages.skema.cache-dan-deployment.item_3' => 'Keep deployments consistent, repeatable, and easy to rollback.',
    'pages.skema.cache-dan-deployment.item_4' => 'Distinguish when you need to regenerate cache and when you need to completely clear cache.',
    'pages.skema.cache-dan-deployment.item_5' => 'Config changes are not read even though the file has been updated.',
    'pages.skema.cache-dan-deployment.item_6' => 'The new route does not appear or the old route is still in use.',
    'pages.skema.cache-dan-deployment.item_7' => 'The old Blade display still appears after deploy.',
    'pages.skema.cache-dan-deployment.item_8' => 'Anomaly issue after rollback/forward deployment.',
    'pages.skema.cache-dan-deployment.item_9' => 'When the system is stable and there is no indication of cache stale.',
    'pages.skema.cache-dan-deployment.lead' => '<code>config:cache</code>, <code>route:cache</code>, <code>view:cache</code>, when to clear cache, and checklist release.',
    'pages.skema.cache-dan-deployment.note_1' => 'If using a supervisor/horizon/queue worker, make sure the worker reads the latest code after deploying.',
    'pages.skema.cache-dan-deployment.note_2' => 'If any step fails, the process stops and the release status changes to failed to prevent partial deploy.',
    'pages.skema.cache-dan-deployment.step_1' => '<code>php artisan route:cache</code>: execute if the entire route is cache compatible (no closure).',
    'pages.skema.cache-dan-deployment.step_10' => '3. Monitor the first 10-30 minutes of application logs.',
    'pages.skema.cache-dan-deployment.step_11' => '4. Validate worker/cron running with the latest code.',
    'pages.skema.cache-dan-deployment.step_12' => '5. Send the completed release status to stakeholders.',
    'pages.skema.cache-dan-deployment.step_13' => '<strong>Rule mandatory:</strong> command sequence must follow the official runbook without skipping steps.',
    'pages.skema.cache-dan-deployment.step_14' => '<strong>Required rule:</strong> migration requires gate approval of at least 2 parties (PIC release + PIC data/tech lead).',
    'pages.skema.cache-dan-deployment.step_15' => '<strong>Required rule:</strong> every release must have a documented rollback plan before execution.',
    'pages.skema.cache-dan-deployment.step_16' => '<strong>Required rule:</strong> releases outside the time window are only permitted for emergencies with approval from the incident commander.',
    'pages.skema.cache-dan-deployment.step_17' => '<strong>Required rule:</strong> post-release smoke test and observability check must be completed before the status is â€œdoneâ€.',
    'pages.skema.cache-dan-deployment.step_18' => '<strong>Optional rule:</strong> use canary/blue-green for high-risk features.',
    'pages.skema.cache-dan-deployment.step_19' => 'Gate 2 - Migration: complete approval and successful migration without errors.',
    'pages.skema.cache-dan-deployment.step_2' => '<code>php artisan view:cache</code>: run to speed up first-hit Blade.',
    'pages.skema.cache-dan-deployment.step_20' => 'Gate 3 - Cache: config/route/view cache regenerate successful.',
    'pages.skema.cache-dan-deployment.step_21' => 'Gate 4 - Runtime: worker restart successful and health check green.',
    'pages.skema.cache-dan-deployment.step_22' => 'Gate 5 - Post-check: smoke test critical endpoint passed.',
    'pages.skema.cache-dan-deployment.step_23' => 'If one of the gates fails, rollback according to the runbook.',
    'pages.skema.cache-dan-deployment.step_24' => '<code>php artisan config:cache</code>: run each release after configuration/application update.',
    'pages.skema.cache-dan-deployment.step_25' => '1. Make sure the branch release is frozen and QA validated.',
    'pages.skema.cache-dan-deployment.step_26' => '1. Smoke test login, dashboard, main transactions, and error pages.',
    'pages.skema.cache-dan-deployment.step_27' => '<strong>Rule mandatory:</strong> production deployment only via default pipeline/script, not random manual commands.',
    'pages.skema.cache-dan-deployment.step_28' => 'Gate 1 - Preflight: all dependencies/builds passed.',
    'pages.skema.cache-dan-deployment.step_3' => '<code>php artisan optimize:clear</code>: use only when troubleshooting cache stale or before full regenerate.',
    'pages.skema.cache-dan-deployment.step_4' => 'Safe sequence: clear as necessary -> regenerate cache -> smoke test.',
    'pages.skema.cache-dan-deployment.step_5' => '2. Verify the migration is safe and have a rollback plan.',
    'pages.skema.cache-dan-deployment.step_6' => '3. Verify the route is compatible for <code>route:cache</code>.',
    'pages.skema.cache-dan-deployment.step_7' => '4. Set up a maintenance message/feature flag if necessary.',
    'pages.skema.cache-dan-deployment.step_8' => '5. Define the deploy PIC, verification PIC, and communication PIC.',
    'pages.skema.cache-dan-deployment.step_9' => '2. Monitor metrics: 4xx/5xx error rate, latency, queue backlog.',
    'pages.skema.cache-dan-deployment.warn_1' => 'Impulsively clearing can increase startup load and extend recovery time.',
    'pages.skema.cache-dan-deployment.warn_2' => 'Without gate approval, migration production cannot be executed.',
