    'pages.skema.data-layer.heading_11' => 'Data Layer Review Checklist (Pre-Merge)',
    'pages.skema.data-layer.heading_12' => '6. No N+1 and no heavy queries without limits.',
    'pages.skema.data-layer.heading_13' => 'Mandatory Transaction Use-Case',
    'pages.skema.data-layer.heading_14' => 'Standard Transaction Template',
    'pages.skema.data-layer.heading_15' => 'Strict Pull Request Gate Review',
    'pages.skema.data-layer.heading_2' => 'End-to-End Data Flow',
    'pages.skema.data-layer.heading_3' => 'Recommended Model Structure & Relationships',
    'pages.skema.data-layer.heading_4' => 'Migration Standards',
    'pages.skema.data-layer.heading_5' => 'Short Migration Example',
    'pages.skema.data-layer.heading_6' => 'Seeder and Factory Strategy',
    'pages.skema.data-layer.heading_7' => 'Recommended Query Patterns',
    'pages.skema.data-layer.heading_8' => 'Example of a Safe Query (List + Filter + Relationship)',
    'pages.skema.data-layer.heading_9' => 'Transactions & Data Consistency',
    'pages.skema.data-layer.item_1' => '<code>app/Models/*</code> for Eloquent entities and relationships.',
    'pages.skema.data-layer.item_10' => 'Use locking as necessary in the race-condition process (stock, balance, document number).',
    'pages.skema.data-layer.item_11' => 'Transactions & Data Consistency',
    'pages.skema.data-layer.item_12' => 'Note slow queries and triggering endpoints.',
    'pages.skema.data-layer.item_13' => 'Audit migration/seeder on release checklist.',
    'pages.skema.data-layer.item_14' => 'Observability and debugging standards',
    'pages.skema.data-layer.item_15' => 'Create an order, create order items, and update stock atomically.',
    'pages.skema.data-layer.item_16' => 'Payment: update invoice, ledger, and order status at once.',
    'pages.skema.data-layer.item_17' => 'Tiered approval process that changes several status tables.',
    'pages.skema.data-layer.item_18' => 'Import a batch that writes parent-child records.',
    'pages.skema.data-layer.item_19' => '<code>database/seeders/*</code> and <code>database/factories/*</code> for initial/testing data.',
    'pages.skema.data-layer.item_2' => '<code>database/migrations/*</code> for the table schema version.',
    'pages.skema.data-layer.item_20' => '<code>app/Providers/AppServiceProvider.php</code> for global guards (e.g. strict mode, lazy loading policy).',
    'pages.skema.data-layer.item_21' => 'If there are external side effects (email, webhook), trigger after a successful transaction.',
    'pages.skema.data-layer.item_22' => 'Add contextual logging (user id, tenant id, request id) when data layer exceptions.',
    'pages.skema.data-layer.item_23' => 'Store reusable query logic in local scopes (for example <code>scopeActive()</code>, <code>scopeForTenant()</code>) so it stays testable.',
    'pages.skema.data-layer.item_3' => 'Use relationship names that are explicit and consistent with the business domain.',
    'pages.skema.data-layer.item_4' => 'Avoid putting presentation logic in the model.',
    'pages.skema.data-layer.item_5' => 'Use factories to build relational data graphs consistently.',
    'pages.skema.data-layer.item_6' => 'Seeder and factory strategy',
    'pages.skema.data-layer.item_7' => 'Separate the demo/testing seeders so they don\'t get mixed up with the production seeds.',
    'pages.skema.data-layer.item_8' => 'Use factories to build relational data graphs consistently.',
    'pages.skema.data-layer.item_9' => 'Wrap the multi-table write process with <code>DB::transaction()</code>.',
    'pages.skema.data-layer.lead' => 'Model structure, relationships, migration, seeders, and query patterns used by the project.',
    'pages.skema.data-layer.code_1' => 'Core relationship examples:',
    'pages.skema.data-layer.note_1' => 'Index combinations must follow real queries, not just add as many indexes as possible.',
    'pages.skema.data-layer.step_1' => '2. The query is executed via the model/scope/query object.',
    'pages.skema.data-layer.step_10' => 'Extract dynamic filters into scope/query objects so controllers stay concise and testable.',
    'pages.skema.data-layer.step_11' => '2. Migration has relevant indexes and foreign keys.',
    'pages.skema.data-layer.step_12' => '3. List queries use minimal select columns + pagination + proper eager loading.',
    'pages.skema.data-layer.step_13' => '4. Multi-entity write operations using transactions.',
    'pages.skema.data-layer.step_14' => '5. Seeder/factory is sufficient for local dev and main test cases.',
    'pages.skema.data-layer.step_15' => '6. No N+1 and no heavy queries without limits.',
    'pages.skema.data-layer.step_16' => '<strong>Mandatory rule:</strong> list endpoints must use pagination; unbounded fetches are prohibited.',
    'pages.skema.data-layer.step_17' => '<strong>Mandatory rule:</strong> maximum <code>3 eager relations</code> per query by default (unless justified in PR).',
    'pages.skema.data-layer.step_18' => '<strong>Mandatory rule:</strong> maximum <code>2 level nested eager loading</code> to keep query complexity under control.',
    'pages.skema.data-layer.step_19' => '<strong>Mandatory rule:</strong> multi-table writes or consistency-critical writes must run inside <code>DB::transaction()</code>.',
    'pages.skema.data-layer.step_2' => '3. Relationship loading must be controlled (selective eager loading).',
    'pages.skema.data-layer.step_20' => '<strong>Mandatory rule:</strong> external side effects (email, webhook, queue dispatch) must execute after transaction commit.',
    'pages.skema.data-layer.step_21' => '<strong>Mandatory rule:</strong> queries inside loops are prohibited unless backed by measured and documented constraints.',
    'pages.skema.data-layer.step_22' => '<strong>Optional rule:</strong> use query caching only for stable read-heavy data with a clear invalidation strategy.',
    'pages.skema.data-layer.step_23' => '2. Include evidence that there is no N+1 on the changed endpoint.',
    'pages.skema.data-layer.step_24' => '3. If eager relation/depth limits are exceeded, a clear technical justification is required in the PR.',
    'pages.skema.data-layer.step_25' => '4. For finance/stock processes, show the transaction boundary and concurrency strategy explicitly.',
    'pages.skema.data-layer.step_26' => '5. Make sure the migration rollback is safe before merging.',
    'pages.skema.data-layer.step_27' => '1. Incoming request -> controller/use-case input validation.',
    'pages.skema.data-layer.step_28' => '1. Explain query impact and new indexes in the PR description.',
    'pages.skema.data-layer.step_29' => 'Migration should be idempotent and easy to trace (one schema change per migration).',
    'pages.skema.data-layer.step_3' => '4. Data is generated into the response/view resource.',
    'pages.skema.data-layer.step_30' => 'Use <code>select()</code> minimal column for endpoint list.',
    'pages.skema.data-layer.step_31' => '1. Models and relationships reflect the domain, not just tables.',
    'pages.skema.data-layer.step_32' => '<strong>Rule is mandatory:</strong> columns used for filter, sort, join, and foreign key must have appropriate indexes.',
    'pages.skema.data-layer.step_4' => '5. Critical write operations are wrapped in transactions.',
    'pages.skema.data-layer.step_5' => 'Add index when adding columns used by filter/sort/join.',
    'pages.skema.data-layer.step_6' => 'Use foreign keys to maintain data integrity, including proper on update/delete rules.',
    'pages.skema.data-layer.step_7' => 'Separate high-risk schema changes (large rename/drop columns) into dedicated migrations and rollout windows.',
    'pages.skema.data-layer.step_8' => 'Use <code>with()</code> or <code>withCount()</code> to prevent N+1 in list/detail endpoints.',
    'pages.skema.data-layer.step_9' => 'Use pagination for large datasets; avoid loading all data into memory.',
    'pages.skema.data-layer.warn_1' => 'Avoid query patterns in loops (<code>N+1</code>). If you find additional queries per item, evaluate eager loading.',
    'pages.skema.data-layer.warn_2' => 'If one use-case results in more than one important table change, the default should be transactions.',
