    'pages.skema.header-menu.item_9' => 'Pages section uses a tabbed mega menu.',
    'pages.skema.header-menu.lead' => 'The header combines several patterns at once: mega menu card, mega menu tab, recursive dropdown, and compact help menu.',
    'pages.skema.header-menu.note_1' => 'One top bar, five different submenu characteristics. This helps UX adapt to each domain content volume.',
    'pages.skema.header-menu.note_2' => 'Best practice: decide the pattern first (mega or dropdown), then define config and partial files so the structure stays consistent.',
    'pages.skema.header-menu.step_1' => 'Dropdown is suitable for short lists with low depth.',
    'pages.skema.header-menu.step_2' => 'Always verify desktop hover behavior and mobile click behavior.',
    'pages.skema.header-menu.step_3' => '<strong>Mandatory rule:</strong> header configuration and renderer partials must stay domain-specific (avoid mixed logic).',
    'pages.skema.header-menu.step_4' => '<strong>Mandatory rule:</strong> route active state must be validated for both desktop hover and mobile click behavior.',
    'pages.skema.header-menu.step_5' => '<strong>Mandatory rule:</strong> external links must explicitly define <code>target</code> and remain safe for UX.',
    'pages.skema.header-menu.step_6' => 'Mega menus are great for large content + visual categorization + CTAs.',
    'pages.skema.header-menu.step_7' => '<strong>Rule mandatory:</strong> new top-level must have a clear pattern (mega/tab/dropdown) before implementation.',
    'pages.skema.i18n-lanjutan.chip_1' => 'stable translation keys',
    'pages.skema.i18n-lanjutan.chip_2' => 'namespace domain',
    'pages.skema.i18n-lanjutan.chip_3' => 'zero hardcoded UI strings',
    'pages.skema.i18n-lanjutan.chip_4' => 'EN/ID key parity',
    'pages.skema.i18n-lanjutan.chip_5' => 'no untranslated keys',
    'pages.skema.i18n-lanjutan.chip_6' => 'domain-reviewed terminology',
    'pages.skema.i18n-lanjutan.heading_1' => 'Key Translation Standards',
    'pages.skema.i18n-lanjutan.heading_10' => 'i18n Team Standard (Strict).',
    'pages.skema.i18n-lanjutan.heading_2' => 'Current i18n Architecture',
    'pages.skema.i18n-lanjutan.heading_3' => 'File Schema and Translation Domain',
    'pages.skema.i18n-lanjutan.heading_4' => 'Key Naming Convention (Strict)',
    'pages.skema.i18n-lanjutan.heading_5' => 'Workflow Add New Language (End-to-End)',
    'pages.skema.i18n-lanjutan.heading_6' => 'Examples of Translational Governance',
    'pages.skema.i18n-lanjutan.heading_7' => 'Fallback Resolution Strategy',
    'pages.skema.i18n-lanjutan.heading_8' => 'i18n QA Checklist',
    'pages.skema.i18n-lanjutan.heading_9' => 'General Risks & Mitigation',
    'pages.skema.i18n-lanjutan.item_1' => 'Use a consistent namespace, for example <code>menu.*</code>, <code>auth.*</code>, <code>pages.*</code>.',
    'pages.skema.i18n-lanjutan.item_10' => 'If the key does not exist in the active locale, fallback to the default locale.',
    'pages.skema.i18n-lanjutan.item_11' => 'If it\'s still not there, display a safe fallback (original title/controlled placeholder).',
    'pages.skema.i18n-lanjutan.item_12' => 'Note missing keys in the QA log so they can be closed before release.',
    'pages.skema.i18n-lanjutan.item_13' => '<strong>Missing key:</strong> create cross-locale key audit script before merge.',
    'pages.skema.i18n-lanjutan.item_14' => '<strong>Inconsistent terms:</strong> use team glossary per business domain.',
    'pages.skema.i18n-lanjutan.item_15' => '<strong>UI broke due to long string:</strong> test responsive EN/ID (and new locale) on mobile+desktop.',
    'pages.skema.i18n-lanjutan.item_16' => '<strong>Mixed languages:</strong> prohibit hardcoded text on reusable components.',
    'pages.skema.i18n-lanjutan.item_17' => '<strong>Incorrect pluralization:</strong> use the framework\'s built-in plural format for the corresponding language.',
    'pages.skema.i18n-lanjutan.item_2' => 'Avoid hardcoded text on Blade for user-facing text.',
    'pages.skema.i18n-lanjutan.item_3' => 'Keep key stable; change the translation value without changing the key if possible.',
    'pages.skema.i18n-lanjutan.item_4' => 'Use lowercase + underscore: <code>menu.skema_cache_and_deployment</code>.',
    'pages.skema.i18n-lanjutan.item_5' => 'Key names must be descriptive, avoid ambiguous abbreviations.',
    'pages.skema.i18n-lanjutan.item_6' => 'One key for one meaning; do not reuse keys for different contexts.',
    'pages.skema.i18n-lanjutan.item_7' => 'If the string needs variables, use consistent placeholders (e.g. <code>:name</code>, <code>:count</code>).',
    'pages.skema.i18n-lanjutan.item_8' => 'Avoid UI position-based keys (e.g. <code>title_1</code>, <code>label_left</code>).',
    'pages.skema.i18n-lanjutan.item_9' => 'Define the default global locale (e.g. <code>en</code> or <code>id</code>).',
    'pages.skema.i18n-lanjutan.lead' => 'Naming key standards, translation governance, and end-to-end process for adding new languages.',
    'pages.skema.i18n-lanjutan.note_1' => 'Separate translation domains for easier change review and fewer merge conflicts.',
    'pages.skema.i18n-lanjutan.step_1' => 'The menu label is resolved from the key <code>menu.*</code> based on the config title.',
    'pages.skema.i18n-lanjutan.step_10' => '3. Check validation messages, flash messages, and error pages.',
    'pages.skema.i18n-lanjutan.step_11' => '4. Check text with placeholders/pluralization.',
    'pages.skema.i18n-lanjutan.step_12' => '5. Check layout overflow for longer strings.',
    'pages.skema.i18n-lanjutan.step_13' => '<strong>Rule required:</strong> PRs that change menu/config must include the corresponding translation key update.',
    'pages.skema.i18n-lanjutan.step_14' => '<strong>Required rule:</strong> must not merge if audit shows missing key in mandatory locale.',
    'pages.skema.i18n-lanjutan.step_15' => '<strong>Required rule:</strong> changes to main domain terminology must be approved by the product/domain owner.',
    'pages.skema.i18n-lanjutan.step_16' => '<strong>Optional rule:</strong> maintain glossary per domain for consistent tone across pages.',
    'pages.skema.i18n-lanjutan.step_17' => 'The locale is stored in the session via the language switch route.',
    'pages.skema.i18n-lanjutan.step_18' => '1. Create a new locale folder: <code>lang/{locale}</code>.',
    'pages.skema.i18n-lanjutan.step_19' => '1. Switch locale from the UI and make sure it persists between pages.',
    'pages.skema.i18n-lanjutan.step_2' => 'If the key does not exist, the system falls back to the original text of the menu title.',
    'pages.skema.i18n-lanjutan.step_20' => '<strong>Rule is mandatory:</strong> all new keys must be added at least in <code>en</code> and <code>id</code>.',
    'pages.skema.i18n-lanjutan.step_3' => 'The main translation sources are currently at <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.skema.i18n-lanjutan.step_4' => '2. Duplicate the baseline file from the default language.',
    'pages.skema.i18n-lanjutan.step_5' => '3. Translate per domain + review glossary of terms.',
    'pages.skema.i18n-lanjutan.step_6' => '4. Register the locale to route switch language and UI options.',
    'pages.skema.i18n-lanjutan.step_7' => '5. Test all menus, auth, validation, and critical pages.',
    'pages.skema.i18n-lanjutan.step_8' => '6. Check for lost fallback keys before release.',
    'pages.skema.i18n-lanjutan.step_9' => '2. Check that the menu/sidebar/header/breadcrumb has been translated.',
    'pages.skema.i18n-lanjutan.warn_1' => 'Renaming translation keys without a usage audit can cause silent fallbacks and UI inconsistencies.',
