    'pages.skema.layout.heading_6' => 'Layout Anti-Patterns',
    'pages.skema.layout.heading_7' => 'Team Standard (Strict) Layout',
    'pages.skema.layout.item_1' => '<code>@@section(\'styles\')</code>: Page-specific CSS.',
    'pages.skema.layout.item_10' => 'Putting business logic in the view/layout.',
    'pages.skema.layout.item_11' => 'Copy-paste the header/sidebar block instead of calling partial.',
    'pages.skema.layout.item_12' => 'Uses redundant inline CSS for quick overrides without documentation.',
    'pages.skema.layout.item_13' => 'Loads all JS plugins in the global layout even if only a few pages are used.',
    'pages.skema.layout.item_2' => '<code>@@section(\'toolbar\')</code>: breadcrumb, title context, action button.',
    'pages.skema.layout.item_3' => '<code>@@section(\'content\')</code>: main content of the page.',
    'pages.skema.layout.item_4' => '<code>@@section(\'scripts\')</code>: Page-specific vendor/custom JS.',
    'pages.skema.layout.item_5' => 'Select the appropriate base layout (generally <code>layouts.index</code>).',
    'pages.skema.layout.item_6' => 'Make sure the <code>toolbar</code> and <code>content</code> sections are clearly defined.',
    'pages.skema.layout.item_7' => 'Use existing partials before creating new markup.',
    'pages.skema.layout.item_8' => 'Add styles/scripts only if needed on the page.',
    'pages.skema.layout.item_9' => 'Test on desktop and mobile to ensure the sidebar/header/drawer stays in sync.',
    'pages.skema.layout.lead' => 'Flow of the layout structure from base template, partial, toolbar, to page content in Metronic Laravel.',
    'pages.skema.layout.note_1' => 'This pattern keeps breadcrumbs, spacing, and visual structure consistent across the page.',
    'pages.skema.layout.step_1' => '2. The page inherits the base layout with <code>@@extends(\'layouts.index\')</code>.',
    'pages.skema.layout.step_2' => '3. The main layout contains partial globals: header, sidebar, footer, drawer, script.',
    'pages.skema.layout.step_3' => '4. Page sections (<code>styles</code>, <code>toolbar</code>, <code>content</code>, <code>scripts</code>) are injected into the layout slot.',
    'pages.skema.layout.step_4' => '5. The Metronic JS component activates menu, drawer, tooltip and widget behavior.',
    'pages.skema.layout.step_5' => '<strong>Rule mandatory:</strong> sections <code>toolbar</code> and <code>content</code> must be explicit.',
    'pages.skema.layout.step_6' => '<strong>Rule required:</strong> reusable markup is extracted to partial/component after repeated use.',
    'pages.skema.layout.step_7' => '<strong>Rule mandatory:</strong> Global layout changes must be tested on at least 3 different pages.',
    'pages.skema.layout.step_8' => '1. Route calls the view page (example: <code>pages.help.programming.scheme.layout</code>).',
    'pages.skema.layout.step_9' => '<strong>Rule required:</strong> new pages must extend <code>layouts.index</code> unless there is an architectural reason.',
    'pages.skema.layout.warn_1' => 'Avoid putting global heavy scripts on all pages if they are only used on one page.',
