    'pages.skema.route.heading_7' => 'Team Standard (Strict) Route',
    'pages.skema.route.heading_8' => 'Route Troubleshooting',
    'pages.skema.route.item_1' => '<code>routes/web.php</code>: custom routes, auth, profile, language switch, bootstrap other routes.',
    'pages.skema.route.item_10' => 'In this project, <code>routes/menu.php</code> and <code>fallback</code> play a big role for the content page.',
    'pages.skema.route.item_11' => '<strong>Route not found:</strong> check blade file naming and location in <code>resources/views/pages</code>.',
    'pages.skema.route.item_12' => '<strong>Route exists but cannot be accessed:</strong> checks auth/verified middleware and login status.',
    'pages.skema.route.item_13' => '<strong>Unread route changes:</strong> run clear/cache command according to the environment.',
    'pages.skema.route.item_14' => '<strong>Conflicting route name:</strong> check results of <code>php artisan route:list</code> for duplication.',
    'pages.skema.route.item_2' => '<code>routes/menu.php</code>: file view based route generator.',
    'pages.skema.route.item_3' => '<code>routes/auth.php</code>: default authentication route.',
    'pages.skema.route.item_4' => 'Create a new Blade file in <code>resources/views/pages</code>.',
    'pages.skema.route.item_5' => 'The route name and URL are generated automatically.',
    'pages.skema.route.item_6' => 'Add a menu configuration if you want it to appear in the navigation.',
    'pages.skema.route.item_7' => 'Routes that are defined first will be evaluated first.',
    'pages.skema.route.item_8' => 'Specific routes must be placed before more generic dynamic routes.',
    'pages.skema.route.item_9' => 'Fallback is always placed last.',
    'pages.skema.route.lead' => 'Request path from URL to Blade in this project: manual route + auto route generator.',
    'pages.skema.route.note_1' => 'All route generators are wrapped in the <code>auth</code> middleware, while the 404 fallback remains outside the middleware.',
    'pages.skema.route.step_1' => '2. <code>routes/web.php</code> processed.',
    'pages.skema.route.step_10' => '<strong>Rule mandatory:</strong> route name must be consistent and descriptive based on the view structure.',
    'pages.skema.route.step_2' => '3. <code>require routes/menu.php</code> is called.',
    'pages.skema.route.step_3' => '4. <code>routes/menu.php</code> scan all <code>resources/views/pages/*.blade.php</code>.',
    'pages.skema.route.step_4' => '5. Each file becomes an automatic GET + route name route in the <code>auth</code> middleware.',
    'pages.skema.route.step_5' => '6. URL does not match -> fallback error 404.',
    'pages.skema.route.step_6' => '<strong>Rule is mandatory:</strong> the internal route of the application page must be protected by middleware <code>auth</code>.',
    'pages.skema.route.step_7' => '<strong>Required rule:</strong> avoid route closure for routes you want to cache.',
    'pages.skema.route.step_8' => '<strong>Rule mandatory:</strong> each new route must appear in <code>route:list</code> during PR review.',
    'pages.skema.route.step_9' => '1. User requests URL.',
    'pages.skema.route.warn_1' => 'Avoid duplicate file names and use the <code>kebab-case</code> format for neat URLs.',
