    'pages.skema.sidebar-menu.heading_7' => 'Team Standard (Strict) Sidebar',
    'pages.skema.sidebar-menu.heading_8' => 'Sidebar Troubleshooting',
    'pages.skema.sidebar-menu.item_1' => '<code>config/sidebar/_sidebar_dashboard.php</code> (dashboard menu + "show more").',
    'pages.skema.sidebar-menu.item_10' => 'Before publishing: validate routes, badges, targets, dropdown behavior, and mobile appearance.',
    'pages.skema.sidebar-menu.item_11' => '<strong>Menu does not appear:</strong> check the correct config file and its array structure.',
    'pages.skema.sidebar-menu.item_12' => '<strong>Title not translated:</strong> check normalization of key <code>menu.*</code> in lang file.',
    'pages.skema.sidebar-menu.item_2' => '<code>config/sidebar/_sidebar_apps.php</code> (nested menus, badges, and dropdowns).',
    'pages.skema.sidebar-menu.item_3' => '<code>config/sidebar/_sidebar_helps.php</code> (internal help document).',
    'pages.skema.sidebar-menu.item_4' => '<strong>Parent does not auto-open:</strong> checks routeIs pattern on active child route.',
    'pages.skema.sidebar-menu.item_5' => '<strong>Icon is empty:</strong> check the icon class and value of <code>paths</code>.',
    'pages.skema.sidebar-menu.item_6' => '<code>resources/views/layouts/partials/sidebar/_menu.blade.php</code> (menu-section wrapper).',
    'pages.skema.sidebar-menu.item_7' => '<code>resources/views/layouts/partials/sidebar/_menu-item.blade.php</code> (recursive item renderer).',
    'pages.skema.sidebar-menu.item_8' => 'Active state parent is calculated recursively, leaf using <code>request()->routeIs($route . \'*\')</code>.',
    'pages.skema.sidebar-menu.item_9' => 'Key title is automatically transformed to <code>menu.*</code>; if the key does not exist it will fallback to the original text.',
    'pages.skema.sidebar-menu.lead' => 'Sidebar uses declarative configuration and a recursive renderer: flexible for nested menus, badges, targets, and dropdowns.',
    'pages.skema.sidebar-menu.note_1' => 'In <code>dropdown => true</code> mode, the current implementation applies the <code>target</code> parent to the child items in the dropdown.',
    'pages.skema.sidebar-menu.step_1' => '<code>children</code> + <code>\'dropdown\' => true</code> renders nested dropdown items.',
    'pages.skema.sidebar-menu.step_2' => '<code>menus_dashboard_collapsed</code> stores additional items in collapsed mode.',
    'pages.skema.sidebar-menu.step_3' => 'The "Show X More" button is calculated dynamically based on collapsed item count.',
    'pages.skema.sidebar-menu.step_4' => 'If the active route is inside collapsed items, the panel expands automatically.',
    'pages.skema.sidebar-menu.step_5' => '<strong>Mandatory rule:</strong> level-1 icons must be valid and the number of <code>paths</code> must match the duotone icon.',
    'pages.skema.sidebar-menu.step_6' => '<strong>Mandatory rule:</strong> menu translation keys must exist in both EN and ID for primary user-facing items.',
    'pages.skema.sidebar-menu.step_7' => '<strong>Mandatory rule:</strong> nested menu changes must be tested for active state down to the deepest level.',
    'pages.skema.sidebar-menu.step_8' => '<code>menus_dashboard</code> = core items that are always shown.',
    'pages.skema.sidebar-menu.step_9' => '<code>children</code> + no <code>dropdown</code> -> accordion.',
    'pages.skema.sidebar-menu.warn_1' => 'Changes in the nested menu structure should be tested on the deepest active route to ensure the automatic parent opens as expected.',
