    'pages.skema.struktur-config-menu.item_1' => '<code>config/sidebar/_sidebar_*.php</code> for sidebar menu per domain.',
    'pages.skema.struktur-config-menu.item_10' => 'Leaf menu is active if <code>request()->routeIs($route . \'*\')</code> true.',
    'pages.skema.struktur-config-menu.item_11' => 'Parent menu is active/open if at least one child is active (recursive).',
    'pages.skema.struktur-config-menu.item_12' => 'Dropdown mode still uses child route evaluation for the active class.',
    'pages.skema.struktur-config-menu.item_13' => 'The dashboard has a special show more/show less treatment from the collapsed config menu.',
    'pages.skema.struktur-config-menu.item_14' => '<strong>Title not translated:</strong> check key <code>menu.*</code> normalization results of title and lang file contents.',
    'pages.skema.struktur-config-menu.item_15' => '<strong>Inactive menu:</strong> check match of route name and wildcard <code>routeIs</code>.',
    'pages.skema.struktur-config-menu.item_16' => '<strong>Icon is empty:</strong> checks the valid icon class and the number of <code>paths</code> according to the duotone icon.',
    'pages.skema.struktur-config-menu.item_17' => '<strong>Unvisible config changes:</strong> clear cache configuration/view if the environment uses cache.',
    'pages.skema.struktur-config-menu.item_2' => '<code>config/header/_header_*.php</code> for mega menu menu/header.',
    'pages.skema.struktur-config-menu.item_3' => '<code>resources/views/layouts/partials/sidebar/_menu.blade.php</code> as sidebar renderer entry.',
    'pages.skema.struktur-config-menu.item_4' => '<code>resources/views/layouts/partials/sidebar/_menu-item.blade.php</code> for recursive rendering of parent/child.',
    'pages.skema.struktur-config-menu.item_5' => '<code>lang/en/menu.php</code> and <code>lang/id/menu.php</code> for translation labels.',
    'pages.skema.struktur-config-menu.item_6' => '<code>app/Helpers/GetPageTitle.php</code> for mapping page titles from the config menu based on the active route.',
    'pages.skema.struktur-config-menu.item_7' => 'Example: <code>Cache & Deployment Scheme</code> -> <code>menu.cache_and_deployment scheme</code>.',
    'pages.skema.struktur-config-menu.item_8' => 'Make sure the same key is available in <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code>.',
    'pages.skema.struktur-config-menu.item_9' => 'If the title changes, the translation key also changes because the key is derived from the title text.',
    'pages.skema.struktur-config-menu.lead' => 'Relations <code>config/sidebar/*</code>, <code>config/header/*</code>, <code>lang/*</code> translation, and Blade renderer.',
    'pages.skema.struktur-config-menu.note_1' => 'Minimum leaf items: <code>title + route</code> or <code>title + href</code>. Parent nodes generally use <code>children</code>.',
    'pages.skema.struktur-config-menu.step_1' => 'The view renderer reads the config to build the UI menu in the sidebar/header.',
    'pages.skema.struktur-config-menu.step_10' => '5. Verify the icon class and <code>paths</code> so that the icon appears perfectly.',
    'pages.skema.struktur-config-menu.step_11' => 'Make sure the route exists (in this project the help route is generated automatically from the blade file name in <code>resources/views/pages</code>).',
    'pages.skema.struktur-config-menu.step_12' => 'Add the title translation key to <code>lang/en/menu.php</code> and <code>lang/id/menu.php</code> if you want multi-language labels.',
    'pages.skema.struktur-config-menu.step_13' => '<code>config/sidebar/*</code> and <code>config/header/*</code> hold the declarative menu structure.',
    'pages.skema.struktur-config-menu.step_14' => '<code>_menu.blade.php</code> calls each config group (dashboard, pages, apps, layouts, help).',
    'pages.skema.struktur-config-menu.step_15' => '1. Add items in the sidebar/header config with a consistent structure.',
    'pages.skema.struktur-config-menu.step_16' => 'Add a new child in <code>children[]</code> with the pair <code>title</code> and <code>route</code>.',
    'pages.skema.struktur-config-menu.step_2' => 'The menu title is converted to the translation key <code>menu.*</code>, fallback to the original text if the key does not yet exist.',
    'pages.skema.struktur-config-menu.step_3' => 'The active route is used to determine <code>active/here/show</code> on parent-child recursively.',
    'pages.skema.struktur-config-menu.step_4' => 'Each item is sent to <code>_menu-item.blade.php</code>.',
    'pages.skema.struktur-config-menu.step_5' => 'If there is <code>children</code>: recursive rendering, parent automatically opens when there is an active child.',
    'pages.skema.struktur-config-menu.step_6' => 'If leaf: render link + badge + state is active based on <code>request()->routeIs(...)</code>.',
    'pages.skema.struktur-config-menu.step_7' => '2. Make sure the route name is valid (<code>php artisan route:list</code>).',
    'pages.skema.struktur-config-menu.step_8' => '3. Add EN and ID translation keys according to title normalization.',
    'pages.skema.struktur-config-menu.step_9' => '4. Check the active state of parent-child on desktop and mobile.',
